```bash #!/usr/bin/env bash # jsb - minimal sing-box manager: AnyTLS / VLESS-Reality / VLESS-WS-TLS  set -Eeuo pipefail umask 077  readonly SCRIPT_URL="https://raw.githubusercontent.com/johanneszhao/Rules/refs/heads/main/jsb.sh" readonly SB_REPO="SagerNet/sing-box" readonly SB_DIR="/etc/sing-box" readonly SB_BIN="$SB_DIR/bin/sing-box" readonly CONF_DIR="$SB_DIR/conf" readonly DATA_DIR="$SB_DIR/data" readonly LOG_DIR="$SB_DIR/logs" readonly SCRIPT_FILE="$SB_DIR/jsb.sh" readonly COMMAND_FILE="/usr/local/bin/jsb" readonly SERVICE_FILE="/etc/systemd/system/sing-box.service" readonly SYSCTL_FILE="/etc/sysctl.d/99-jsb-network.conf" readonly REALITY_SNI="www.tesla.com"  red() { printf '\033[31m%s\033[0m\n' "$*"; } green() { printf '\033[32m%s\033[0m\n' "$*"; } yellow() { printf '\033[33m%s\033[0m\n' "$*"; } die() { red "错误: $*" >&2; exit 1; }  require_root() { [[ ${EUID:-$(id -u)} -eq 0 ]] || die "请使用 root 用户运行。" }  check_system() { command -v systemctl >/dev/null 2>&1 || die "仅支持使用 systemd 的 Linux。" case "$(uname -m)" in x86_64|amd64) SB_ARCH="amd64" ;; aarch64|arm64) SB_ARCH="arm64" ;; *) die "仅支持 amd64 和 arm64，当前架构: $(uname -m)" ;; esac }  install_dependencies() { green "安装依赖..." if command -v apt-get >/dev/null 2>&1; then apt-get update -y DEBIAN_FRONTEND=noninteractive apt-get install -y curl ca-certificates tar openssl jq iproute2 qrencode elif command -v dnf >/dev/null 2>&1; then dnf install -y curl ca-certificates tar openssl jq iproute qrencode elif command -v yum >/dev/null 2>&1; then yum install -y curl ca-certificates tar openssl jq iproute qrencode else die "仅支持 apt、dnf 或 yum。" fi }  public_ip() { local ip ip=$(curl -4fsS --retry 3 --connect-timeout 5 --max-time 10 https://api.ipify.org 2>/dev/null || true) [[ -n $ip ]] || ip=$(curl -6fsS --retry 3 --connect-timeout 5 --max-time 10 https://api64.ipify.org 2>/dev/null || true) [[ -n $ip ]] || die "无法获取公网 IP。" if [[ $ip == *:* ]]; then printf '[%s]' "$ip"; else printf '%s' "$ip"; fi }  random_port() { local port i for ((i=0; i<300; i++)); do port=$((RANDOM % 64535 + 1000)) if ! ss -H -lntu 2>/dev/null | awk '{print $5}' | grep -Eq "(^|:)$port$"; then printf '%s' "$port" return fi done die "无法找到可用端口。" }  core_version() { "$SB_BIN" version 2>/dev/null | awk 'NR==1 { for (i=1;i<=NF;i++) if ($i ~ /^[0-9]+\./) { print "v" $i; exit } }' }  version_ge_114() { local version major minor version="${1#v}" major="${version%%.*}" version="${version#*.}" minor="${version%%.*}" (( major > 1 || (major == 1 && minor >= 14) )) }  download_core() { local version archive url tmp extracted green "获取 sing-box 最新版本..." version=$(curl -fsSL --retry 3 "https://api.github.com/repos/$SB_REPO/releases/latest?v=$RANDOM" | jq -er '.tag_name') \ || die "获取 sing-box 版本失败。" tmp=$(mktemp -d) trap 'rm -rf "${tmp:-}"' RETURN archive="$tmp/sing-box.tar.gz" url="https://github.com/$SB_REPO/releases/download/$version/sing-box-${version#v}-linux-$SB_ARCH.tar.gz" green "下载 sing-box $version..." curl -fL --retry 5 --connect-timeout 10 "$url" -o "$archive" || die "下载 sing-box 失败。" mkdir -p "$SB_DIR/bin" tar -xzf "$archive" -C "$tmp" extracted=$(find "$tmp" -type f -name sing-box -perm -u+x | head -n1) [[ -n $extracted ]] || die "压缩包中未找到 sing-box。" install -m 755 "$extracted" "$SB_BIN" "$SB_BIN" version >/dev/null || die "sing-box 内核无法运行。" trap - RETURN rm -rf "$tmp" }  write_base_config() { mkdir -p "$CONF_DIR" "$DATA_DIR" "$LOG_DIR" cat > "$CONF_DIR/00-base.json" <<EOF { "log": { "level": "warn", "output": "$LOG_DIR/sing-box.log", "timestamp": true }, "outbounds": [ { "type": "direct", "tag": "direct" } ] } EOF }  install_service() { cat > "$SERVICE_FILE" <<EOF [Unit] Description=sing-box service managed by jsb After=network-online.target nss-lookup.target Wants=network-online.target  [Service] Type=simple User=root ExecStart=$SB_BIN run -C $CONF_DIR -D $DATA_DIR ExecReload=/bin/kill -HUP \$MAINPID Restart=on-failure RestartSec=2s LimitNOFILE=1048576 NoNewPrivileges=true  [Install] WantedBy=multi-user.target EOF systemctl daemon-reload systemctl enable sing-box >/dev/null }  install_shortcut() { mkdir -p "$SB_DIR" if [[ -r ${BASH_SOURCE[0]} && ${BASH_SOURCE[0]} != /dev/fd/* && ${BASH_SOURCE[0]} != /proc/self/fd/* ]]; then install -m 755 "${BASH_SOURCE[0]}" "$SCRIPT_FILE" else curl -fsSL --retry 3 "$SCRIPT_URL?v=$RANDOM" -o "$SCRIPT_FILE" || die "安装 jsb 快捷脚本失败。" chmod 755 "$SCRIPT_FILE" fi ln -sfn "$SCRIPT_FILE" "$COMMAND_FILE" }  optimize_network() { green "应用 BBR 和保守的网络调优..." modprobe tcp_bbr 2>/dev/null || true cat > "$SYSCTL_FILE" <<'EOF' net.core.default_qdisc = fq net.ipv4.tcp_congestion_control = bbr net.ipv4.tcp_fastopen = 3 net.core.rmem_max = 33554432 net.core.wmem_max = 33554432 net.ipv4.tcp_rmem = 4096 87380 33554432 net.ipv4.tcp_wmem = 4096 65536 33554432 net.core.somaxconn = 8192 net.core.netdev_max_backlog = 16384 net.ipv4.tcp_mtu_probing = 1 net.ipv4.tcp_slow_start_after_idle = 0 EOF sysctl -p "$SYSCTL_FILE" >/dev/null 2>&1 || yellow "部分 sysctl 参数不受当前内核支持，已跳过。" green "拥塞控制: $(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || printf unknown)" }  check_all() { local output if ! output=$("$SB_BIN" check -C "$CONF_DIR" 2>&1); then red "配置检查失败:" printf '%s\n' "$output" >&2 return 1 fi }  commit_node() { local tmp_file=$1 final_file=$2 mv "$tmp_file" "$final_file" if ! check_all; then rm -f "$final_file" red "已自动删除本次生成的无效配置。" return 1 fi if ! systemctl restart sing-box; then rm -f "$final_file" systemctl restart sing-box 2>/dev/null || true red "服务启动失败，本次配置已回滚。" journalctl -u sing-box -n 20 --no-pager >&2 || true return 1 fi }  show_link() { local link=$1 printf '\n%s\n' "$link" if command -v qrencode >/dev/null 2>&1; then printf '\n' qrencode -t ANSIUTF8 "$link" || true fi }  add_anytls() { local port password name cert key tmp_file final_file addr link addr=$(public_ip) port=$(random_port) password=$(openssl rand -hex 16) name="anytls-$port" cert="$DATA_DIR/$name.crt" key="$DATA_DIR/$name.key" tmp_file="$CONF_DIR/.$name.json.tmp" final_file="$CONF_DIR/$name.json"  openssl req -x509 -newkey ec -pkeyopt ec_paramgen_curve:prime256v1 -sha256 -nodes \ -days 3650 -subj "/CN=localhost" -keyout "$key" -out "$cert" >/dev/null 2>&1 \ || die "生成 AnyTLS 自签证书失败。"  cat > "$tmp_file" <<EOF { "inbounds": [ { "type": "anytls", "tag": "$name", "listen": "::", "listen_port": $port, "tcp_fast_open": true, "users": [ { "password": "$password" } ], "tls": { "enabled": true, "certificate_path": "$cert", "key_path": "$key" } } ] } EOF commit_node "$tmp_file" "$final_file" || { rm -f "$cert" "$key" "$tmp_file"; return 1; } link="anytls://$password@$addr:$port?insecure=1&allowInsecure=1#$name" green "AnyTLS 节点已创建。" show_link "$link" }  add_reality() { local port uuid keys private_key public_key short_id name tmp_file final_file addr link addr=$(public_ip) port=$(random_port) uuid=$("$SB_BIN" generate uuid) keys=$("$SB_BIN" generate reality-keypair) private_key=$(awk -F': *' 'tolower($1) ~ /private/ {print $2; exit}' <<< "$keys") public_key=$(awk -F': *' 'tolower($1) ~ /public/ {print $2; exit}' <<< "$keys") [[ -n $private_key && -n $public_key ]] || die "生成 Reality 密钥失败。" short_id=$(openssl rand -hex 8) name="reality-$port" tmp_file="$CONF_DIR/.$name.json.tmp" final_file="$CONF_DIR/$name.json"  cat > "$tmp_file" <<EOF { "inbounds": [ { "type": "vless", "tag": "$name", "listen": "::", "listen_port": $port, "tcp_fast_open": true, "users": [ { "uuid": "$uuid", "flow": "xtls-rprx-vision" } ], "tls": { "enabled": true, "server_name": "$REALITY_SNI", "reality": { "enabled": true, "handshake": { "server": "$REALITY_SNI", "server_port": 443 }, "private_key": "$private_key", "short_id": [ "$short_id" ] } } } ], "outbounds": [ { "type": "direct", "tag": "public_key_$public_key" } ] } EOF commit_node "$tmp_file" "$final_file" || { rm -f "$tmp_file"; return 1; } link="vless://$uuid@$addr:$port?encryption=none&flow=xtls-rprx-vision&security=reality&sni=$REALITY_SNI&fp=chrome&pbk=$public_key&sid=$short_id&type=tcp#$name" green "VLESS-Reality 节点已创建。" show_link "$link" }  valid_domain() { [[ $1 =~ ^([A-Za-z0-9]([A-Za-z0-9-]{0,61}[A-Za-z0-9])?\.)+[A-Za-z]{2,63}$ ]] }  port_available() { local port=$1 ! ss -H -lnt 2>/dev/null | awk '{print $4}' | grep -Eq "(^|:)$port$" }  add_ws_tls() { local domain uuid path name version tmp_file final_file tls_json encoded_path link read -r -p "请输入已解析到本机的域名: " domain domain="${domain,,}" valid_domain "$domain" || die "域名格式不正确。" port_available 443 || die "443 端口已被占用，无法直接申请证书并运行 WS-TLS。"  uuid=$("$SB_BIN" generate uuid) path="/$uuid" name="vless-ws-tls-$domain" version=$(core_version) [[ -n $version ]] || die "无法识别 sing-box 版本。" tmp_file="$CONF_DIR/.$name.json.tmp" final_file="$CONF_DIR/$name.json"  if version_ge_114 "$version"; then tls_json="\"certificate_provider\": { \"type\": \"acme\", \"domain\": [ \"$domain\" ] }" else tls_json="\"acme\": { \"domain\": [ \"$domain\" ] }" fi  cat > "$tmp_file" <<EOF { "inbounds": [ { "type": "vless", "tag": "$name", "listen": "::", "listen_port": 443, "tcp_fast_open": true, "users": [ { "uuid": "$uuid" } ], "tls": { "enabled": true, "server_name": "$domain", $tls_json }, "transport": { "type": "ws", "path": "$path", "early_data_header_name": "Sec-WebSocket-Protocol" } } ] } EOF commit_node "$tmp_file" "$final_file" || { rm -f "$tmp_file"; return 1; } encoded_path="%2F$uuid" link="vless://$uuid@$domain:443?encryption=none&security=tls&sni=$domain&type=ws&host=$domain&path=$encoded_path#$name" green "VLESS-WS-TLS 节点已创建。" show_link "$link" }  list_nodes() { local files file shopt -s nullglob files=("$CONF_DIR"/*.json) green "已安装节点:" for file in "${files[@]}"; do [[ $(basename "$file") == "00-base.json" ]] && continue printf ' %s\n' "$(basename "$file" .json)" done ((${#files[@]} <= 1)) && printf ' 暂无节点\n' shopt -u nullglob }  delete_node() { local files choice file cert key shopt -s nullglob files=("$CONF_DIR"/*.json) shopt -u nullglob local nodes=() for file in "${files[@]}"; do [[ $(basename "$file") == "00-base.json" ]] || nodes+=("$file") done ((${#nodes[@]} > 0)) || { yellow "暂无可删除节点。"; return; } printf '请选择要删除的节点:\n' select file in "${nodes[@]}" "取消"; do [[ $file == "取消" ]] && return [[ -n $file ]] || { red "无效选择。"; continue; } cert="$DATA_DIR/$(basename "$file" .json).crt" key="$DATA_DIR/$(basename "$file" .json).key" rm -f "$file" "$cert" "$key" check_all && systemctl restart sing-box green "节点已删除。" return done }  repair_config() { write_base_config find "$CONF_DIR" -maxdepth 1 -type f -name '.*.tmp' -delete 2>/dev/null || true if check_all; then systemctl restart sing-box green "基础配置已重建，全部节点检查通过。" else red "基础配置已重建，但现有节点中仍有无效配置；请删除对应节点。" return 1 fi }  update_script() { local tmp tmp=$(mktemp) curl -fsSL --retry 3 "$SCRIPT_URL?v=$RANDOM" -o "$tmp" || { rm -f "$tmp"; die "下载脚本失败。"; } bash -n "$tmp" || { rm -f "$tmp"; die "远程脚本语法检查失败，拒绝更新。"; } install -m 755 "$tmp" "$SCRIPT_FILE" ln -sfn "$SCRIPT_FILE" "$COMMAND_FILE" rm -f "$tmp" green "jsb 脚本已更新。" }  uninstall_all() { local answer yellow "将删除 sing-box、全部节点、证书、日志和 jsb 网络调优。" read -r -p "确认完整卸载？[y/N]: " answer [[ $answer =~ ^[Yy]$ ]] || { yellow "已取消。"; return; } systemctl disable --now sing-box >/dev/null 2>&1 || true rm -f "$SERVICE_FILE" "$COMMAND_FILE" "$SYSCTL_FILE" rm -rf "$SB_DIR" systemctl daemon-reload sysctl --system >/dev/null 2>&1 || true green "已完整卸载。" }  status_service() { systemctl status sing-box --no-pager -l || true }  install_all() { check_system install_dependencies download_core write_base_config install_service install_shortcut optimize_network check_all || die "基础配置检查失败。" systemctl restart sing-box green "安装完成。输入 jsb 打开菜单。" }  menu() { while true; do printf '\n===== jsb sing-box 管理菜单 =====\n' printf ' 1) 添加 AnyTLS (随机端口/密码)\n' printf ' 2) 添加 Reality (随机端口/密钥，Tesla SNI)\n' printf ' 3) 添加 VLESS-WS-TLS (域名/自动证书)\n' printf ' 4) 查看节点\n' printf ' 5) 删除节点\n' printf ' 6) 服务状态\n' printf ' 7) 重启服务\n' printf ' 8) 修复并检查配置\n' printf ' 9) 更新 jsb 脚本\n' printf ' 10) 完整卸载\n' printf ' 0) 退出\n' read -r -p "请选择: " choice case "$choice" in 1) add_anytls ;; 2) add_reality ;; 3) add_ws_tls ;; 4) list_nodes ;; 5) delete_node ;; 6) status_service ;; 7) check_all && systemctl restart sing-box && green "服务已重启。" ;; 8) repair_config ;; 9) update_script ;; 10) uninstall_all; return ;; 0) return ;; *) red "无效选择。" ;; esac done }  main() { require_root check_system case "${1:-}" in install) [[ -x $SB_BIN ]] && die "sing-box 已安装，请直接运行 jsb。" install_all menu ;; anytls) [[ -x $SB_BIN ]] || die "请先安装。"; add_anytls ;; reality) [[ -x $SB_BIN ]] || die "请先安装。"; add_reality ;; ws|vless) [[ -x $SB_BIN ]] || die "请先安装。"; add_ws_tls ;; list|ls) list_nodes ;; delete|del|rm) delete_node ;; status|s) status_service ;; restart|r) check_all && systemctl restart sing-box ;; repair|check) repair_config ;; update) update_script ;; uninstall|un) uninstall_all ;; "") if [[ -x $SB_BIN ]]; then menu; else install_all; menu; fi ;; *) die "未知命令: $1" ;; esac }  main "$@" ```  ## 安装  ```bash curl -fsSL "https://raw.githubusercontent.com/johanneszhao/Rules/refs/heads/main/jsb.sh?v=$RANDOM" -o /tmp/jsb.sh bash -n /tmp/jsb.sh && bash /tmp/jsb.sh ```  也支持进程替换：  ```bash bash <(curl -fsSL "https://raw.githubusercontent.com/johanneszhao/Rules/refs/heads/main/jsb.sh?v=$RANDOM") ```  安装后运行：  ```bash jsb ```
